}

export function TopAppBar({
  pageTitle,
  breadcrumb,
  user,
  onSearch,
  notifications = 0,
  className,
}: TopAppBarProps) {
  const router = useRouter()
  const [searchQuery, setSearchQuery] = React.useState('')

  React.useEffect(() => {
    const timer = setTimeout(() => {
      onSearch?.(searchQuery)
    }, 300)
    return () => clearTimeout(timer)
  }, [searchQuery, onSearch])

  const handleLogout = async () => {
    try {
      await signOut()
      router.push('/login')
    } catch (err: any) {
      console.error('Logout error:', err)
    }
  }

  return (
    <header className={cn(
      "sticky top-0 w-full z-40 bg-surface/80 backdrop-blur-md border-b border-outline-variant/15 shadow-ambient-sm",
      className
    )}>
      <div className="flex justify-between items-center px-8 py-4 max-w-7xl mx-auto">
        {/* Left: Breadcrumb */}
        <div className="flex items-center gap-4">
          {breadcrumb && breadcrumb.length > 0 && (
            <nav className="flex items-center gap-2 text-sm text-secondary">
              {breadcrumb.map((item, index) => (
                <React.Fragment key={item.label}>
                  {index > 0 && (
                    <span className="material-symbols-outlined text-[14px] text-outline-variant">
                      chevron_right
                    </span>
                  )}
                  {item.href ? (
                    <a
                      href={item.href}
                      className="hover:text-primary transition-colors"
                    >
                      {item.label}
                    </a>
                  ) : (
                    <span className="text-primary font-semibold">{item.label}</span>
                  )}
                </React.Fragment>
              ))}
            </nav>
          )}
        </div>

        {/* Right: Actions */}
        <div className="flex items-center gap-4">
          {/* Search */}
          {onSearch && (
            <div className="relative hidden md:block">
              <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-outline text-sm">
                search
              </span>
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Tìm kiếm..."
                className="pl-10 pr-4 py-2 bg-surface-container-low border-none rounded-full text-sm w-64 focus:ring-2 focus:ring-primary/20 focus:bg-surface-container-lowest transition-all placeholder:text-outline/60"
              />
            </div>
          )}

          {/* Notifications */}
          <Button variant="ghost" size="icon" className="relative">
            <span className="material-symbols-outlined">notifications</span>
            {notifications > 0 && (
              <span className="absolute top-2 right-2 w-2 h-2 bg-error rounded-full" />
            )}
          </Button>

          {/* Help */}
          <Button variant="ghost" size="icon">
            <span className="material-symbols-outlined">help_outline</span>
          </Button>

          {/* User Menu */}
          {user && (
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" className="relative h-10 w-10 rounded-full">
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={user.avatar} alt={user.name} />
                    <AvatarFallback className="bg-primary-container text-on-primary font-semibold">
                      {user.name.charAt(0).toUpperCase()}
                    </AvatarFallback>
                  </Avatar>
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent className="w-56" align="end" forceMount>
                <DropdownMenuLabel className="font-normal">
                  <div className="flex flex-col space-y-1">
                    <p className="text-sm font-medium leading-none">{user.name}</p>
                    <p className="text-xs leading-none text-secondary">{user.email}</p>
                  </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator />
                <DropdownMenuItem>
                  <span className="material-symbols-outlined mr-2 text-sm">person</span>
                  Hồ sơ
                </DropdownMenuItem>
                <DropdownMenuItem>
                  <span className="material-symbols-outlined mr-2 text-sm">settings</span>
                  Cài đặt
                </DropdownMenuItem>
                <DropdownMenuItem>
                  <span className="material-symbols-outlined mr-2 text-sm">help</span>
                  Hỗ trợ
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem className="text-error" onClick={handleLogout}>
                  <span className="material-symbols-outlined mr-2 text-sm">logout</span>
                  Đăng xuất
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          )}
        </div>
      </div>
    </header>
  )
}
'use client'

import * as React from 'react'
import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { cn } from '@/lib/utils'

interface NavItem {
  icon: string
  label: string
  href: string
  badge?: number
}

interface SideNavBarProps {
  role: 'student' | 'lecturer' | 'admin'
  userName?: string
  userAvatar?: string
  onLogout?: () => void
}

const studentNavItems: NavItem[] = [
  { icon: 'dashboard', label: 'Bảng điều khiển', href: '/student' },
  { icon: 'lightbulb', label: 'Đề tài gợi ý', href: '/student/proposals' },
  { icon: 'how_to_reg', label: 'Đăng ký', href: '/student/registration' },
  { icon: 'trending_up', label: 'Tiến độ', href: '/student/submissions' },
