        const data = await api.student.appointments.list()
        setAppointments((data || []).map((apt: any) => ({
          id: apt.id,
          lecturer_id: apt.lecturer_id,
          lecturer_name: apt.lecturer_name,
          lecturer_email: apt.lecturer_email,
