                <div className="flex gap-2 pt-4 border-t">
                  {selectedAppointment.meeting_link && selectedAppointment.status === 'scheduled' && (
                    <Button
                      onClick={() => window.open(selectedAppointment.meeting_link, '_blank')}
                      className="flex-1 bg-primary hover:bg-primary/90"
                    >
                      <span className="material-symbols-outlined text-sm mr-2">video_call</span>
                      Tham gia
                    </Button>
                  )}
                  {selectedAppointment.status === 'scheduled' && (
                    <Button
                      onClick={() => {
                        setIsDetailModalOpen(false)
                        setIsRescheduleModalOpen(true)
                      }}
                      variant="outline"
                      className="flex-1"
                    >
                      <span className="material-symbols-outlined text-sm mr-2">reschedule</span>
                      Đổi lịch
                    </Button>
                  )}
                </div>
              </div>
            </DialogContent>
          </Dialog>

          {/* Reschedule Request Modal */}
          <Dialog open={isRescheduleModalOpen} onOpenChange={setIsRescheduleModalOpen}>
            <DialogContent className="max-w-lg">
              <DialogHeader>
                <DialogTitle>Yêu Cầu Đổi Lịch</DialogTitle>
              </DialogHeader>
              <div className="space-y-4 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="reason">Lý do đổi lịch *</Label>
                  <Textarea
                    id="reason"
                    value={rescheduleReason}
                    onChange={(e) => setRescheduleReason(e.target.value)}
                    placeholder="Trình bày lý do bạn muốn đổi lịch hẹn..."
                    rows={4}
                  />
                </div>
                <div className="flex gap-2">
                  <Button
                    onClick={handleRescheduleRequest}
                    disabled={!rescheduleReason.trim()}
                    className="flex-1"
                  >
                    Gửi yêu cầu
                  </Button>
                  <Button
                    onClick={() => {
                      setIsRescheduleModalOpen(false)
                      setRescheduleReason('')
                    }}
                    variant="outline"
                    className="flex-1"
                  >
                    Hủy
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </>
      )}
    </Shell>
  )
}

function getTypeLabel(type: string): string {
  const labels: Record<string, string> = {
    meeting: 'Họp',
    defense: 'Bảo vệ',
    feedback: 'Phản hồi',
    office_hour: 'Giờ tiếp sinh viên',
  }
  return labels[type] || type
}

function getStatusLabel(status: string): string {
  const labels: Record<string, string> = {
    scheduled: 'Đã lên lịch',
    confirmed: 'Đã xác nhận',
    cancelled: 'Đã hủy',
    completed: 'Hoàn thành',
    no_show: 'Không tham gia',
  }
  return labels[status] || status
}

function formatDate(dateStr: string): string {
  const date = new Date(dateStr)
  return date.toLocaleDateString('vi-VN', {
    day: 'numeric',
    month: 'numeric',
    year: 'numeric',
  })
}

function formatTime(dateStr: string): string {
  const date = new Date(dateStr)
  return date.toLocaleTimeString('vi-VN', {
    hour: '2-digit',
    minute: '2-digit',
  })
}

function formatDateTime(dateStr: string): string {
  const date = new Date(dateStr)
  return date.toLocaleDateString('vi-VN', {
    weekday: 'long',
    hour: '2-digit',
    minute: '2-digit',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  })
}

